# Invoice line-item calculation (Python)
def compute_gst(
    base_amount: float,
    buyer_state: str,
    seller_state: str = 'MH',  # Maharashtra (Mumbai)
    is_export: bool = False,
) -> dict:
    SAC_CODE = '998314'
    GST_RATE = 0.18
    if is_export:
        return {'base': base_amount, 'igst': 0.0, 'cgst': 0.0,
                'sgst': 0.0, 'total': base_amount, 'sac': SAC_CODE,
                'note': 'Zero-rated export — LUT filed'}
    if buyer_state == seller_state:  # intra-state
        half = round(base_amount * GST_RATE / 2, 2)
        return {'base': base_amount, 'cgst': half, 'sgst': half,
                'igst': 0.0, 'total': base_amount + half * 2, 'sac': SAC_CODE}
    else:  # inter-state
        igst = round(base_amount * GST_RATE, 2)
        return {'base': base_amount, 'igst': igst, 'cgst': 0.0,
                'sgst': 0.0, 'total': base_amount + igst, 'sac': SAC_CODE}

# Late-payment interest calculation
from datetime import date
from decimal import Decimal

def late_interest(
    invoice_amount: Decimal,   # base amount before GST
    invoice_date: date,
    payment_date: date,
    grace_days: int = 30,
    annual_rate: Decimal = Decimal('0.18'),
) -> Decimal:
    """Returns simple interest on overdue invoice (GST-free)."""
    due_date = invoice_date + __import__('datetime').timedelta(days=grace_days)
    if payment_date <= due_date:
        return Decimal('0')
    overdue_days = (payment_date - due_date).days
    # Simple interest: P × R × D / 365
    return (invoice_amount * annual_rate * overdue_days / 365).quantize(
        Decimal('0.01')
    )
